711	// memory compares pods by largest consumer of memory relative to request.
712	func memory(stats statsFunc) cmpFunc {
713		return func(p1, p2 *v1.Pod) int {
714			p1Stats, p1Found := stats(p1)
715			p2Stats, p2Found := stats(p2)
716			if !p1Found || !p2Found {
717				// prioritize evicting the pod for which no stats were found
718				return cmpBool(!p1Found, !p2Found)
719			}
720	
721			// adjust p1, p2 usage relative to the request (if any)
722			p1Memory := memoryUsage(p1Stats.Memory)
723			p1Request := v1resource.GetResourceRequestQuantity(p1, v1.ResourceMemory)
724			p1Memory.Sub(p1Request)
725	
726			p2Memory := memoryUsage(p2Stats.Memory)
